import{_ as o,c as t,o as i,a4 as a}from"./chunks/framework.BxjRYGQi.js";const h=JSON.parse('{"title":"Agilebot Robotics - ROS2 Software Package","description":"","frontmatter":{},"headers":[],"relativePath":"en/index.md","filePath":"en/index.md"}'),r={name:"en/index.md"};function n(l,e,s,c,d,g){return i(),t("div",{"data-pagefind-body":!0},e[0]||(e[0]=[a('<h1 id="agilebot-robotics-ros2-software-package" tabindex="-1">Agilebot Robotics - ROS2 Software Package <a class="header-anchor" href="#agilebot-robotics-ros2-software-package" aria-label="Permalink to “Agilebot Robotics - ROS2 Software Package”">​</a></h1><h2 id="project-overview" tabindex="-1">Project Overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to “Project Overview”">​</a></h2><p>This project provides a ROS2 toolkit for Agilebot robots, designed to help users quickly integrate and develop robotic applications. The toolkit includes:</p><ol><li><p><strong>Collaborative Robot URDF Model</strong><br> Provides standardized URDF description files for 3D modeling and simulation.</p></li><li><p><strong>ROS2 Driver Package</strong><br> Implements robot control and communication functions, supporting:</p><ul><li>Execution of control programs</li><li>Sending program scripts to the robot</li><li>Retrieving robot status information (joint/end-effector data, alarm information, etc.)</li><li>Displaying the robot&#39;s current posture</li></ul></li><li><p><strong>Example Code and Tutorials</strong><br> Includes typical application cases to guide users in:</p><ul><li>Motion planning with MoveIt and execution on Agilebot robots</li><li>Importing and executing offline trajectory files</li><li>Integrating Agilebot&#39;s vision software AgileGaze</li><li>Sending custom program scripts</li><li>Vision-based palletizing demo</li></ul></li></ol><p>This toolkit reduces integration complexity and improves development efficiency through comprehensive development resources.</p><h2 id="documentation-directory" tabindex="-1">Documentation Directory <a class="header-anchor" href="#documentation-directory" aria-label="Permalink to “Documentation Directory”">​</a></h2><ul><li><a href="./01-installation/">Installation Guide</a></li><li><a href="./02-quick-start/">Quick Start</a></li><li><a href="./03-example/">Examples</a></li><li><a href="./04-faq/">FAQ</a></li><li><a href="./05-roadmap/">Roadmap</a></li><li><a href="./06-license/">License</a></li></ul><h2 id="contact-information" tabindex="-1">Contact Information <a class="header-anchor" href="#contact-information" aria-label="Permalink to “Contact Information”">​</a></h2><p>If you have any suggestions or want to contribute to this project, please contact us through the following methods:</p><ul><li><strong>Company Website</strong>: <a href="https://www.sh-agilebot.com/" target="_blank" rel="noreferrer">https://www.sh-agilebot.com/</a></li><li><strong>Email</strong>: <a href="mailto:info@agilebot.com.cn" target="_blank" rel="noreferrer">info@agilebot.com.cn</a></li><li><strong>Phone</strong>: <code>400-996-7588</code></li><li><strong>GitHub</strong>: <a href="https://github.com/sh-agilebot/Agilebot_Robot_Ros2" target="_blank" rel="noreferrer">https://github.com/sh-agilebot/Agilebot_Robot_Ros2</a></li></ul>',10)]))}const m=o(r,[["render",n]]);export{h as __pageData,m as default};
